import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_name, framework, package_id) -> version
def build_lookup(data):
    lookup = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                lookup[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

before = build_lookup(baseline)
after_l = build_lookup(after)

all_keys = sorted(set(before.keys()) | set(after_l.keys()))

changes = []
unchanged = []
for key in all_keys:
    proj, fw, pkg = key
    b_ver = before.get(key, '-')
    a_ver = after_l.get(key, '-')
    if b_ver != a_ver:
        if b_ver == '-':
            changes.append((proj, fw, pkg, b_ver, a_ver, 'Added'))
        elif a_ver == '-':
            changes.append((proj, fw, pkg, b_ver, a_ver, 'Removed'))
        else:
            changes.append((proj, fw, pkg, b_ver, a_ver, 'Aligned to highest version'))
    else:
        unchanged.append((proj, fw, pkg, a_ver))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]} [{c[5]}]')
else:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}): {u[2]} = {u[3]}')
